insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published) values
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'corredor-iniciante', 'Corredor Iniciante', 'Começa a correr agora ou retorna ao esporte', '{"emoji":"🏃","name":"Corredor Iniciante","tag":"Começa a correr agora ou retorna ao esporte","tags":["Corrida","Iniciante","GPS"],"sinais":["Nunca usou relógio GPS","Fala de \"começar a correr\"","Pergunta o modelo mais simples","Quer monitorar tempo e distância"],"comunicacao":["Forerunner 55 é a porta de entrada ideal","Forerunner 165 para quem quer tela AMOLED premium desde o início","Fale dos planos de treino adaptativos: é como ter um técnico","Mostre como sincroniza com o celular facilmente"],"produtos":["Forerunner 55","Forerunner 165"],"primario":"Forerunner 55","objections":[{"q":"Tá caro, vou pesquisar online.","a":"Entendo perfeitamente. Mas aqui você tem garantia direta com a Proparts — importadora oficial —, suporte técnico presencial e pode experimentar agora."},{"q":"Preciso de todas essas funções?","a":"O FR55 tem exatamente o que você precisa para começar: GPS, frequência cardíaca e treinos básicos. Sem complicação — você aprende a usar em minutos."}]}'::jsonb, 0, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'corredor-dedicado', 'Corredor Dedicado', 'Treina com frequência e busca evolução', '{"emoji":"🏅","name":"Corredor Dedicado","tag":"Treina com frequência e busca evolução","tags":["Corrida","Intermediário","Métricas"],"sinais":["Já usa relógio com GPS básico","Corre 3+ vezes por semana","Fala em ritmo, treino intervalado, PR","Pergunta por precisão e métricas mais avançadas"],"comunicacao":["FR265 ou 570 — GPS multibanda e métricas completas","Fale do Training Readiness: saber o dia certo para treinar forte","PacePRO para quem quer estratégia de prova","Destaque o ecossistema: Strava, TrainingPeaks, Stryd"],"produtos":["Forerunner 265","Forerunner 570","Forerunner 965"],"primario":"Forerunner 265","objections":[{"q":"O FR165 já não é suficiente?","a":"O FR165 é ótimo para iniciar. O FR265 adiciona GPS multibanda — muito mais preciso em cidades."},{"q":"Qual a diferença real do 265 pro 570?","a":"O 570 é o lançamento 2025 com sensor óptico de 5ª geração (Elevate Gen 5), mais preciso em alta intensidade."}]}'::jsonb, 1, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'atleta-de-elite-triatleta', 'Atleta de Elite / Triatleta', 'Alto volume de treino, competições, multiesporte', '{"emoji":"🏆","name":"Atleta de Elite / Triatleta","tag":"Alto volume de treino, competições, multiesporte","tags":["Corrida","Triathlon","Elite","Natação","Ciclismo"],"sinais":["Menciona triathlon, Ironman, ultra","Pergunta por bateria longa e GPS preciso","Já tem relógio mas quer upgrade","Treina mais de 10h por semana"],"comunicacao":["FR955 ou 965 — ferramentas de triatleta","Fenix 8 para quem também faz outdoor","Bateria 30h+ GPS real, não estimada","Training Readiness para periodização"],"produtos":["Forerunner 955","Forerunner 965","Forerunner 970","Fenix 8"],"primario":"Forerunner 970","objections":[{"q":"O FR955 não mudou muito do 945.","a":"O 955 trouxe GPS multibanda, sensor HRV Status, Training Readiness e carregamento solar."},{"q":"Fenix ou FR970?","a":"O FR970 é o top de corrida — cristal de safira, lanterna LED integrada, 32GB. O Fenix 8 adiciona alto-falante, mic, mergulho."}]}'::jsonb, 2, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'aventureiro-trilheiro', 'Aventureiro / Trilheiro', 'Ama trilhas, camping, aventura outdoor', '{"emoji":"🌿","name":"Aventureiro / Trilheiro","tag":"Ama trilhas, camping, aventura outdoor","tags":["Trilha","Outdoor","Trekking","Aventura"],"sinais":["Fala de trilha, serra, montanha","Pergunta por GPS com mapa topográfico","Quer algo resistente e com bateria longa","Menciona acampamento ou expedição"],"comunicacao":["Instinct 3 — MIL-STD-810, certificação militar de robustez, bateria 26 dias","Fenix 8 para quem quer o máximo em outdoor e também faz esporte","Destaque mapas TopoActive e trilhas offline","Inclua o inReach para expedições longas sem sinal"],"produtos":["Instinct 3","Fenix 8","Enduro 3"],"primario":"Instinct 3","objections":[{"q":"O celular com mapa offline não resolve?","a":"O celular tem bateria de horas. O Instinct 3 tem bateria de 26 dias. Em trilha longa, sem energia, o GPS integrado pode ser a diferença entre se perder ou não."},{"q":"O que é MIL-STD-810?","a":"É a certificação militar americana de resistência: testes de impacto, temperatura extrema, umidade, altitude e vibração."}]}'::jsonb, 3, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'mulher-lifestyle', 'Mulher Lifestyle', 'Quer design elegante com funções inteligentes', '{"emoji":"💎","name":"Mulher Lifestyle","tag":"Quer design elegante com funções inteligentes","tags":["Lifestyle","Feminino","Design","Presente"],"sinais":["Pergunta por relógio menor ou mais bonito","Quer monitoramento de saúde feminina","Compra de presente para ela","Compara com Apple Watch no design"],"comunicacao":["Lily 2 — o menor e mais elegante da Garmin, design joia","Lily 2 Active — Lily com GPS integrado para quem corre ou caminha","Venu 4 — AMOLED premium com saúde feminina completa","O Garmin tem saúde feminina completa: ciclo, gravidez, menopausa"],"produtos":["Lily 2","Lily 2 Active","Venu 4"],"primario":"Lily 2 Active","objections":[{"q":"O Apple Watch tem mais funções de smartwatch.","a":"O Apple Watch tem um ecosistema forte, mas a bateria dura 1-2 dias com GPS. O Lily 2 Active tem GPS integrado e bateria de até 7 dias."},{"q":"Prefiro algo maior e mais completo.","a":"O Venu 4 tem tela AMOLED grande e premium, com todas as funções de saúde. Posso mostrar os dois para comparar no pulso?"}]}'::jsonb, 4, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'ciclista', 'Ciclista', 'Pedala com frequência — estrada, MTB ou casual', '{"emoji":"🚴","name":"Ciclista","tag":"Pedala com frequência — estrada, MTB ou casual","tags":["Ciclismo","MTB","Estrada","Bike"],"sinais":["Menciona bike, MTB, estrada, gravel","Pergunta por GPS para guidão","Fala de Strava, Komoot, subidas","Quer medir cadência ou potência"],"comunicacao":["Edge 540/840 para quem quer GPS no guidão com tela maior","FR970 ou Fenix 8 para quem já tem relógio e quer multiesporte","Varia RTL515 — radar traseiro que detecta carros a 140m","Rally RK 200 — pedal medidor de potência SPD"],"produtos":["Edge 550","Edge 850","Edge 1050","Varia RTL515","Rally RK 200"],"primario":"Edge 850","objections":[{"q":"Uso o celular no suporte.","a":"O celular no sol laga, esquenta e a tela escurece. O Edge foi feito para isso: tela legível sob sol forte, modo específico para MTB e bateria que dura toda a etapa."},{"q":"Para que medidor de potência?","a":"Potência é a métrica mais honesta do ciclismo — não é afetada por cansaço, calor ou adrenalina."}]}'::jsonb, 5, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'nadador-triatleta', 'Nadador / Triatleta', 'Nada regularmente ou compete em triathlon', '{"emoji":"🏊","name":"Nadador / Triatleta","tag":"Nada regularmente ou compete em triathlon","tags":["Natação","Piscina","Triathlon","Aquático"],"sinais":["Fala de piscina, mar, braçadas","Pergunta por relógio à prova d''água para natação","Quer SWOLF ou eficiência de braçada","Menciona triathlon ou duathlon"],"comunicacao":["FR970 ou FR965 — métricas completas de natação + ciclismo + corrida","Fenix 8 para o triatleta que quer o máximo","HRM 600 para registrar FC dentro da água","SWOLF: quanto menor, mais eficiente"],"produtos":["Forerunner 970","Forerunner 965","Fenix 8","HRM 600"],"primario":"Forerunner 970","objections":[{"q":"Não existe relógio que funcione bem na água.","a":"O Garmin têm resistência à água de 5 ATM. O FR970 reconhece automaticamente o tipo de braçada, conta voltas e mede SWOLF."}]}'::jsonb, 6, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'mergulhador', 'Mergulhador', 'Pratica mergulho recreativo ou técnico', '{"emoji":"🤿","name":"Mergulhador","tag":"Pratica mergulho recreativo ou técnico","tags":["Mergulho","Dive","Aquático"],"sinais":["Menciona profundidade, descompressão, nitrox","Pergunta sobre computador de mergulho","Fala de mergulho técnico ou trimix"],"comunicacao":["Descent G1/G2 para mergulho recreativo","Descent Mk3i para técnico sério","Descent X30 com autonomia de gás e modo técnico","Destaque: smartwatch completo fora da água"],"produtos":["Descent G1","Descent G2","Descent Mk3i","Descent X30"],"primario":"Descent G2","objections":[{"q":"Prefiro um computador de mergulho separado.","a":"Computadores separados não têm GPS de superfície, mapas ou monitoramento de saúde. O Descent faz tudo isso e é um smartwatch completo no dia a dia."}]}'::jsonb, 7, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'golfista', 'Golfista', 'Joga golfe com regularidade', '{"emoji":"⛳","name":"Golfista","tag":"Joga golfe com regularidade","tags":["Golfe","Golf"],"sinais":["Fala de green, par, bunker, handicap","Pergunta por GPS de golfe","Usa luvas de golfe ou tem look do esporte"],"comunicacao":["Approach S44 para entrada com +42.000 campos","Approach S50 para a experiência mais completa com AMOLED","Destaque distâncias automáticas do green","Scorecard digital e estatísticas de handicap"],"produtos":["Approach S44","Approach S50"],"primario":"Approach S50","objections":[{"q":"O app no celular já tem distâncias.","a":"O app serve, mas durante o swing você não vai olhar para o celular. O relógio no pulso mostra a distância instantaneamente, sem tirar o foco do jogo."}]}'::jsonb, 8, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'motociclista', 'Motociclista', 'Piloto de moto, quer GPS robusto para viagens', '{"emoji":"🏍️","name":"Motociclista","tag":"Piloto de moto, quer GPS robusto para viagens","tags":["Moto","Viagem","GPS"],"sinais":["Fala de viagem de moto, rota, estrada","Pergunta por GPS para moto","Usa acessórios de motociclismo"],"comunicacao":["Zumo XT2 é o GPS específico para moto da Garmin","Tela resistente a luvas, antirreflexo, suporta chuva","Roteamento evita ruas proibidas para motos","Integração com capacete Bluetooth"],"produtos":["Zumo XT2"],"primario":"Zumo XT2","objections":[{"q":"O celular no suporte não é suficiente?","a":"O Zumo XT2 é feito para ser visto com luvas sob sol forte. Não esquenta, não buga, não depende de plano de dados."}]}'::jsonb, 9, true),
  ((select id from brands where slug = 'garmin'), 'perfil_cliente', 'pescador-nautico', 'Pescador / Náutico', 'Pesca em rios, represas ou mar', '{"emoji":"🎣","name":"Pescador / Náutico","tag":"Pesca em rios, represas ou mar","tags":["Pesca","Náutico","GPS"],"sinais":["Menciona pesca em represa, rio ou mar","Fala de barco, canoa, lancha","Pergunta sobre sonar ou ecobatímetro"],"comunicacao":["Striker 4 para pescador que quer o básico","Striker Vivid 5cv para quem quer ClearVü","ECHOMAP UHD2 para navegador sério com mapas náuticos","GPS marca os pontos de pesca para voltar depois"],"produtos":["Striker 4","Striker Vivid 5cv","ECHOMAP UHD2 52cv","GPSMAP 79","GPSMAP 86"],"primario":"Striker Vivid 5cv","objections":[{"q":"Uso o celular para mapas no barco.","a":"Celular não tem sonar e a tela não aguenta sol forte, maresia e vibrações. O Striker e ECHOMAP são feitos para isso."},{"q":"Preciso mesmo do ECHOMAP se o Vivid já tem GPS?","a":"O Vivid tem GPS básico. O ECHOMAP adiciona mapas náuticos detalhados com profundidade de canais e pontos de referência."}]}'::jsonb, 10, true)
