  ((select id from brands where slug = 'garmin'), 'produto', 'forerunner-170', 'Forerunner 170', 'NOVO 2026.', '{"name":"Forerunner 170","s":"Forerunner","cat":"forerunner","lvl":2,"para":"Corredor Iniciante / Dedicado","dest":"NOVO 2026. AMOLED + Elevate Gen 4. Compacto (menor que o 165). Relatório noturno, despertador inteligente, registro de estilo de vida. Mais perfis de atividade. Sem multibanda. Sem triathlon (multiesporte a partir do 265)."}'::jsonb, 3, true),
