  ((select id from brands where slug = 'garmin'), 'produto', 'forerunner-970', 'Forerunner 970', 'Cristal safira + lanterna LED + 32GB.', '{"name":"Forerunner 970","s":"Forerunner","cat":"forerunner","lvl":5,"para":"Atleta de Elite","dest":"Cristal safira + lanterna LED + 32GB. Top absoluto da linha Forerunner."}'::jsonb, 8, true),
  ((select id from brands where slug = 'garmin'), 'produto', 'fenix-e', 'Fenix E', 'Entrada da linha Fenix.', '{"name":"Fenix E","s":"Fenix","cat":"outdoor","lvl":3,"para":"Atleta / Aventureiro intermediário","dest":"Entrada da linha Fenix. AMOLED + GPS padrão + mapas TopoActive. Robusto, sem alto-falante/mic e sem GPS multibanda."}'::jsonb, 9, true),
