  ((select id from brands where slug = 'garmin'), 'produto', 'etrex-22x', 'eTrex 22x', 'Entrada da linha eTrex.', '{"name":"eTrex 22x","s":"eTrex","cat":"gps","lvl":1,"para":"Caminhante / Iniciante","dest":"Entrada da linha eTrex. Robusto, simples, mapas TopoActive. Bateria AA."}'::jsonb, 37, true),
  ((select id from brands where slug = 'garmin'), 'produto', 'etrex-32x', 'eTrex 32x', 'eTrex 22x + bússola 3 eixos + altímetro barométrico.', '{"name":"eTrex 32x","s":"eTrex","cat":"gps","lvl":2,"para":"Trilheiro / Trekking","dest":"eTrex 22x + bússola 3 eixos + altímetro barométrico. Bússola real."}'::jsonb, 38, true),
  ((select id from brands where slug = 'garmin'), 'produto', 'etrex-solar', 'eTrex Solar', 'Carregamento solar + bateria de até 100h.', '{"name":"eTrex Solar","s":"eTrex","cat":"gps","lvl":3,"para":"Expedição / Ultra","dest":"Carregamento solar + bateria de até 100h. Para expedições longas."}'::jsonb, 39, true),
