  ((select id from brands where slug = 'garmin'), 'produto', 'inreach-mini-3', 'inReach Mini 3', 'Mini 2 + tela colorida touch + GPS multibanda + sirene.', '{"name":"inReach Mini 3","s":"inReach","cat":"gps","lvl":3,"para":"Aventureiro / Expedição","dest":"Mini 2 + tela colorida touch + GPS multibanda + sirene. Versão atual."}'::jsonb, 41, true),
