  ((select id from brands where slug = 'garmin'), 'produto', 'zumo-xt2', 'Zumo XT2', 'GPS para moto.', '{"name":"Zumo XT2","s":"Zumo","cat":"moto","lvl":4,"para":"Motociclista","dest":"GPS para moto. Tela resistente a luvas, chuva e sol. Roteamento anti-pedágio."}'::jsonb, 45, true),
  ((select id from brands where slug = 'garmin'), 'produto', 'striker-4', 'Striker 4', 'Sonar 3.5" com GPS básico.', '{"name":"Striker 4","s":"Striker","cat":"marine","lvl":1,"para":"Pescador Iniciante","dest":"Sonar 3.5\" com GPS básico. Entrada acessível para pesca."}'::jsonb, 46, true),
