  ((select id from brands where slug = 'garmin'), 'produto', 'echomap-uhd2-52cv', 'ECHOMAP UHD2 52cv', 'Chartplotter + sonar UHD2 5".', '{"name":"ECHOMAP UHD2 52cv","s":"ECHOMAP","cat":"marine","lvl":3,"para":"Pescador/Navegador","dest":"Chartplotter + sonar UHD2 5\". Mapas BlueChart G3."}'::jsonb, 48, true),
  ((select id from brands where slug = 'garmin'), 'produto', 'hrm-200', 'HRM 200', 'Monitor cardíaco de peito.', '{"name":"HRM 200","s":"HRM","cat":"acess","lvl":2,"para":"Corredor / Ciclista","dest":"Monitor cardíaco de peito. Precisão superior ao óptico de pulso."}'::jsonb, 49, true),
