insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published) values
  ((select id from brands where slug = 'garmin'), 'faq', 'qual-a-diferenca-entre-garmin-connect-e-connect-iq', 'Qual a diferença entre Garmin Connect e Connect IQ?', 'Garmin Connect é o app de sincronização — recebe dados do relógio e integra com Strava, Apple Health etc.', '{"q":"Qual a diferença entre Garmin Connect e Connect IQ?","a":"Garmin Connect é o app de sincronização — recebe dados do relógio e integra com Strava, Apple Health etc. Connect IQ é a loja de apps que rodam DENTRO do relógio, como Spotify, Wikiloc e Woo."}'::jsonb, 0, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-garmin-tem-spotify', 'O Garmin tem Spotify?', 'Sim!', '{"q":"O Garmin tem Spotify?","a":"Sim! Nos modelos com armazenamento interno (FR265, 570, 955, 965, 970, Fenix 8, Venu 4 e outros). Baixe o app Spotify pela Connect IQ Store, sincronize playlists via Wi-Fi e ouça offline com fones Bluetooth."}'::jsonb, 1, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-garmin-funciona-sem-celular', 'O Garmin funciona sem celular?', 'Sim.', '{"q":"O Garmin funciona sem celular?","a":"Sim. O GPS é embutido no relógio. Você sai para correr sem celular e registra todos os dados. A sincronização acontece depois, quando você conecta via Bluetooth."}'::jsonb, 2, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'quanto-tempo-dura-a-bateria', 'Quanto tempo dura a bateria?', 'Em smartwatch (sem GPS): FR55 ~2 semanas, Instinct 3 ~26 dias, Fenix 8 ~18 dias.', '{"q":"Quanto tempo dura a bateria?","a":"Em smartwatch (sem GPS): FR55 ~2 semanas, Instinct 3 ~26 dias, Fenix 8 ~18 dias. Em GPS ativo: FR55 ~20h, FR955 ~30h, Enduro 3 ~70h. OBS: GPS multibanda consome ~30-40% mais."}'::jsonb, 3, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'qual-a-diferenca-entre-gps-multibanda-e-gps-comum', 'Qual a diferença entre GPS multibanda e GPS comum?', 'O GPS comum usa uma frequência de satélite.', '{"q":"Qual a diferença entre GPS multibanda e GPS comum?","a":"O GPS comum usa uma frequência de satélite. O multibanda usa duas (L1 e L5) simultaneamente, resultando em traçado muito mais preciso em cidades com prédios, florestas e montanhas."}'::jsonb, 4, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-sensor-de-fc-no-pulso-e-preciso', 'O sensor de FC no pulso é preciso?', 'Preciso em intensidade moderada.', '{"q":"O sensor de FC no pulso é preciso?","a":"Preciso em intensidade moderada. Em atividades de alta intensidade, recomendamos o HRM de peito (HRM 200 ou HRM 600) para máxima precisão."}'::jsonb, 5, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-que-e-o-vo2-max-da-garmin', 'O que é o VO2 Max da Garmin?', 'Estimativa do consumo máximo de oxigênio calculada pelo algoritmo FirstBeat, baseada na relação entre FC e velocidade.', '{"q":"O que é o VO2 Max da Garmin?","a":"Estimativa do consumo máximo de oxigênio calculada pelo algoritmo FirstBeat, baseada na relação entre FC e velocidade. É um excelente indicador de evolução aeróbica."}'::jsonb, 6, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-que-e-o-body-battery', 'O que é o Body Battery?', 'Indicador de energia de 0-100 baseado em HRV, sono, estresse e atividade.', '{"q":"O que é o Body Battery?","a":"Indicador de energia de 0-100 baseado em HRV, sono, estresse e atividade. Sobe com sono de qualidade, cai com estresse e exercício. Ajuda o atleta a saber o melhor momento para treinar."}'::jsonb, 7, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-garmin-monitora-sono', 'O Garmin monitora sono?', 'Sim.', '{"q":"O Garmin monitora sono?","a":"Sim. Todos os modelos com sensor de FC monitoram sono automaticamente: fases (leve, profundo, REM), SpO2 noturno e pontuação de sono. Dados disponíveis no Garmin Connect pela manhã."}'::jsonb, 8, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-garmin-funciona-com-android-e-iphone', 'O Garmin funciona com Android e iPhone?', 'Sim.', '{"q":"O Garmin funciona com Android e iPhone?","a":"Sim. O Garmin Connect é compatível com iOS e Android. Apple Health sincroniza apenas em iPhones."}'::jsonb, 9, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-garmin-tem-nfc-para-pagamento', 'O Garmin tem NFC para pagamento?', 'Sim, via Garmin Pay nos modelos compatíveis: Fenix 8, FR265, 570, 955, 965, 970, Venu 4, Vivoactive 6 e outros.', '{"q":"O Garmin tem NFC para pagamento?","a":"Sim, via Garmin Pay nos modelos compatíveis: Fenix 8, FR265, 570, 955, 965, 970, Venu 4, Vivoactive 6 e outros."}'::jsonb, 10, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'qual-a-garantia-oferecida-pela-proparts', 'Qual a garantia oferecida pela Proparts?', 'A Proparts oferece 2 anos de garantia para todos os dispositivos Garmin e 1 ano para acessórios.', '{"q":"Qual a garantia oferecida pela Proparts?","a":"A Proparts oferece 2 anos de garantia para todos os dispositivos Garmin e 1 ano para acessórios. Para acionar, é necessário apenas o cadastro completo no sistema."}'::jsonb, 11, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-edge-e-diferente-do-relogio-para-ciclismo', 'O Edge é diferente do relógio para ciclismo?', 'Sim.', '{"q":"O Edge é diferente do relógio para ciclismo?","a":"Sim. O Edge é um ciclocomputador fixado no guidão — tela maior, ideal para ver dados em velocidade. Relógios como FR965 ou Fenix 8 também registram ciclismo com precisão."}'::jsonb, 12, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'o-inreach-mini-precisa-de-assinatura-para-funcionar', 'O inReach Mini precisa de assinatura para funcionar?', 'Sim.', '{"q":"O inReach Mini precisa de assinatura para funcionar?","a":"Sim. Sem assinatura ativa, as funções via satélite ficam desativadas. Existe o plano Enabled (~US$7,99/mês) para SOS de emergência. É possível suspender por até 12 meses sem custo."}'::jsonb, 13, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'qual-a-diferenca-entre-hrm-200-e-hrm-600', 'Qual a diferença entre HRM 200 e HRM 600?', 'O HRM 200 é para corrida e ciclismo — não armazena atividades.', '{"q":"Qual a diferença entre HRM 200 e HRM 600?","a":"O HRM 200 é para corrida e ciclismo — não armazena atividades. O HRM 600 é para corrida, natação e triatlo — armazena as atividades internamente, inclusive embaixo da água."}'::jsonb, 14, true),
  ((select id from brands where slug = 'garmin'), 'faq', 'qual-rede-de-satelites-o-inreach-utiliza', 'Qual rede de satélites o inReach utiliza?', 'O inReach usa a rede de satélites Iridium®, que oferece cobertura global de 100% do planeta — incluindo oceanos, polos e áreas sem qualquer cobertura de celular.', '{"q":"Qual rede de satélites o inReach utiliza?","a":"O inReach usa a rede de satélites Iridium®, que oferece cobertura global de 100% do planeta — incluindo oceanos, polos e áreas sem qualquer cobertura de celular."}'::jsonb, 15, true)
insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published) values
  ((select id from brands where slug = 'garmin'), 'concorrente', 'apple-watch', 'Apple Watch', 'O concorrente mais citado.', '{"name":"Apple Watch","badge":"⚠️ Principal","bc":"orange","desc":"O concorrente mais citado. Forte em design e integração com iPhone. Fraco em bateria e precisão esportiva.","rows":[{"a":"Bateria GPS","g":"30h+ (FR955) / 70h (Enduro)","t":"~6-18h dependendo do modelo"},{"a":"Precisão GPS","g":"Multibanda + múltiplos satélites","t":"GPS básico (Ultra tem dual frequency)"},{"a":"Foco esportivo","g":"Ferramenta de atleta — FirstBeat","t":"Smartwatch com função esportiva"},{"a":"Bateria diária","g":"Dias ou semanas","t":"1-2 dias"},{"a":"Compatibilidade","g":"iOS e Android","t":"Exclusivo iPhone"}]}'::jsonb, 0, true),
  ((select id from brands where slug = 'garmin'), 'concorrente', 'polar', 'Polar', 'Referência em análise científica de treino.', '{"name":"Polar","badge":"⚠️ Principal","bc":"orange","desc":"Referência em análise científica de treino. Boa análise, mas ecossistema menor.","rows":[{"a":"Análise de treino","g":"FirstBeat — líder de mercado","t":"Excelente — base acadêmica"},{"a":"GPS","g":"Multibanda nos modelos avançados","t":"Preciso mas sem multibanda na maioria"},{"a":"Apps no relógio","g":"Connect IQ com centenas de apps","t":"Ecossistema menor"},{"a":"Bateria","g":"Dias ou semanas","t":"Até ~40h GPS nos top"}]}'::jsonb, 1, true),
  ((select id from brands where slug = 'garmin'), 'concorrente', 'coros', 'Coros', 'Marca chinesa com preço agressivo.', '{"name":"Coros","badge":"⚡ Crescente","bc":"blue","desc":"Marca chinesa com preço agressivo. Principal argumento do cliente sensível a preço.","rows":[{"a":"Preço","g":"Premium — qualidade justifica","t":"Até 30-40% mais barato"},{"a":"Ecossistema","g":"Connect IQ + 50+ integrações","t":"Ecossistema em desenvolvimento"},{"a":"Suporte no Brasil","g":"Rede oficial Proparts","t":"Suporte mais limitado"},{"a":"Histórico","g":"+35 anos no mercado","t":"Marca recente (2012)"}]}'::jsonb, 2, true),
  ((select id from brands where slug = 'garmin'), 'concorrente', 'samsung-galaxy-watch', 'Samsung Galaxy Watch', 'Forte em design e Android.', '{"name":"Samsung Galaxy Watch","badge":"💡 Lifestyle","bc":"blue","desc":"Forte em design e Android. Não compete em esporte de performance.","rows":[{"a":"Bateria","g":"Dias ou semanas com GPS","t":"1-3 dias com GPS ativo"},{"a":"Esportes avançados","g":"Algoritmos específicos por modalidade","t":"Modo esportivo básico"},{"a":"Compatibilidade","g":"iOS e Android","t":"Melhor com Samsung Android"}]}'::jsonb, 3, true),
  ((select id from brands where slug = 'garmin'), 'concorrente', 'suunto', 'Suunto', 'Herança em outdoor e mergulho.', '{"name":"Suunto","badge":"🌿 Nicho Outdoor","bc":"blue","desc":"Herança em outdoor e mergulho. Qualidade, mas ecossistema menor.","rows":[{"a":"Outdoor / Trilha","g":"Fenix 8, Instinct 3 — referência","t":"Suunto 9 é boa proposta"},{"a":"Mergulho","g":"Série Descent — mais completa","t":"Tradição em dive computers"},{"a":"Integrações","g":"Connect IQ + dezenas","t":"Ecossistema mais limitado"},{"a":"Distribuição BR","g":"Rede Proparts ampla","t":"Distribuição mais restrita"}]}'::jsonb, 4, true)
