-- ============================================================================
-- GARMIN TRAINING HUB — SEED 040: BIBLIOTECA TÉCNICA (content_library)
-- ============================================================================
-- Migração de dados reais do protótipo estático index_redesign_v5.html para a
-- tabela genérica content_library (ver sql/002_content_library_schema.sql).
-- Fonte: arrays JS "profiles", "prods", "faqs", "comps" e "sports" do protótipo.
--
-- Cobertura desta seed (contagem real dos arrays de origem, na data da migração):
--   perfil_cliente  : 11 personas de cliente
--   produto         : 53 produtos do catálogo
--   faq             : 16 perguntas frequentes
--   concorrente     : 5 comparativos com concorrentes
--   especialidade   : 10 especialidades por esporte
--   TOTAL           : 95 linhas
--
-- payload jsonb guarda fielmente TODOS os campos originais do objeto JS de cada
-- item (nomes de chave mantidos como no protótipo: emoji, tag, sinais, comunicacao,
-- produtos, primario, objections, s, cat, lvl, para, dest, q, a, badge, bc, desc,
-- rows, metrics — conforme a categoria). Nada foi resumido, traduzido ou inventado.
--
-- Pré-requisito: garmin_training_hub_migrations.sql (tabela brands) e
-- sql/002_content_library_schema.sql (tabela content_library) já aplicados.
-- ============================================================================

-- ============================================================================
-- 1. PERFIS DE CLIENTE (category = 'perfil_cliente') — 11 personas
-- ============================================================================
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 2. PRODUTOS (category = 'produto') — 53 itens do catálogo
-- ============================================================================
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 3. FAQ (category = 'faq') — 16 perguntas frequentes
-- ============================================================================
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 4. CONCORRENTES (category = 'concorrente') — 5 comparativos
-- ============================================================================
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 5. ESPECIALIDADES POR ESPORTE (category = 'especialidade') — 10 esportes
-- ============================================================================
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- FIM DA SEED 040
-- ============================================================================
